emm not a timing issue🤔 can't we do it like this, I don't test it but I guess it can works.

```diff
diff --git a/src/nvim/buffer.c b/src/nvim/buffer.c
index 829d4d2392..62f70dbc29 100644
--- a/src/nvim/buffer.c
+++ b/src/nvim/buffer.c
@@ -4046,7 +4046,7 @@ bool bt_dontwrite_msg(const buf_T *const buf)

 /// @return  true if the buffer should be hidden, according to 'hidden', ":hide"
 ///          and 'bufhidden'.
-bool buf_hide(const buf_T *const buf)
+bool buf_hide(buf_T* const buf)
   FUNC_ATTR_PURE
 {
   // 'bufhidden' overrules 'hidden' and ":hide", check it first
@@ -4058,6 +4058,10 @@ bool buf_hide(const buf_T *const buf)
   case 'h':
     return true;            // "hide"
   }
+  // prompt buffer can always be abandoned even when modified
+  if (bt_prompt(buf)) {
+    return true;
+  }
   return p_hid || (cmdmod.cmod_flags & CMOD_HIDE);
 }
```

